selector_to_html = {"a[href=\"onboard_computer.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.3 </span>On-board Computer<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>The AgiBot X2 Ultra comes standard with a motion control computing unit, an interaction computing unit, and a developer computing unit, providing stronger computational power and greater flexibility for complex tasks and advanced applications.</p>", "a[href=\"SDK_interface.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.5 </span>Secondary Development Interfaces (Ultra Edition)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"joint_name_and_limit.html#id5\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.7.4 </span>Waist Motion Range<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"user_debug_interface.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.4 </span>User Debug Interfaces (Ultra Edition)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"part_name.html#x2-ultra\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.1.1 </span>X2 Ultra Edition<a class=\"headerlink\" href=\"#x2-ultra\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"sensor_fov.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.6.1 </span>Sensor Capabilities &amp; FOV Diagram<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"robot_specifications.html#x2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.2.1 </span>X2 Series Parameter<a class=\"headerlink\" href=\"#x2\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"coordinate_system.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.8 </span>Coordinate System<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>When all joint angles are at their zero positions, the coordinate systems of each robot component are distributed as shown in the figure below. <strong>Red indicates the X-axis, green indicates the Y-axis, and blue indicates the Z-axis</strong>.</p>", "a[href=\"sensor_fov.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.6.2 </span>Sensor Specifications<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>LiDAR<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"joint_name_and_limit.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.7.1 </span>Arm Motion Range<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"part_name.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.1 </span>Product Overview<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">1.1.1 </span>X2 Ultra Edition<a class=\"headerlink\" href=\"#x2-ultra\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#agibot-x2\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1 </span><i class=\"fa-brands fa-bilibili\"></i> About AgiBot X2<a class=\"headerlink\" href=\"#agibot-x2\" title=\"Link to this heading\">\uf0c1</a></h1>", "a[href=\"sensor_fov.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.6 </span>AgiBot X2 Sensor Overview<a class=\"headerlink\" href=\"#x2\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">1.6.1 </span>Sensor Capabilities &amp; FOV Diagram<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"joint_name_and_limit.html#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.7.2 </span>Leg Motion Range<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"joint_name_and_limit.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.7 </span>Joint Motion Range Description (Warranted)<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><h2><span class=\"section-number\">1.7.1 </span>Arm Motion Range<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"joint_name_and_limit.html#id4\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.7.3 </span>Head Motion Range<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"onboard_computer.html#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.3.1 </span>Standard Computing Units<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"onboard_computer.html#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.3.2 </span>Development Computing Unit Specifications<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"robot_specifications.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.2 </span>Robot Specifications<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p>The <strong>AgiBot X2 Series</strong> is equipped with a comprehensive set of <strong>hardware and system resources</strong>, including the <strong>mechanical structure</strong>, <strong>sensor systems</strong>, <strong>communication interfaces</strong>, <strong>computing units, and power systems</strong>. With this highly integrated architecture, the AgiBot X2 enables <strong>complex whole-body motion control</strong>, <strong>intelligent perception and environmental interaction</strong>, and supports <strong>advanced secondary development</strong> through <strong>AimDK</strong>.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
